import { Injectable } from '@angular/core';
import { HttpClient, HttpErrorResponse, HttpHeaders } from '@angular/common/http';
import { Observable, throwError, BehaviorSubject, of } from 'rxjs';
import { catchError, tap, map, switchMap } from 'rxjs/operators';
import { CartItem } from '../models/models';
import { AuthService } from './auth.service';

@Injectable({
  providedIn: 'root'
})
export class CartService {
  private apiUrl = 'http://localhost:3000/api/cart';
  private cartCountSubject = new BehaviorSubject<number>(0);
  public cartCount$ = this.cartCountSubject.asObservable();
  private cartItemsSubject = new BehaviorSubject<CartItem[]>([]);
  public cartItems$ = this.cartItemsSubject.asObservable();

  constructor(
    private http: HttpClient,
    private authService: AuthService
  ) {
    // Initialize cart count if user is logged in
    if (this.authService.isLoggedIn()) {
      this.refreshCart();
    }

    // Subscribe to auth changes to reset cart on logout
    this.authService.currentUser.subscribe(user => {
      if (!user) {
        this.clearLocalCart();
      } else {
        this.refreshCart();
      }
    });
  }

  /**
   * Refresh cart from server
   */
  refreshCart(): void {
    if (!this.authService.isLoggedIn()) {
      this.clearLocalCart();
      return;
    }
    
    this.getCartItems().subscribe({
      next: (items) => {
        console.log('Cart refreshed:', items.length, 'items');
      },
      error: (error) => {
        console.error('Error refreshing cart:', error);
      }
    });
  }

  /**
   * Get all cart items for the logged-in user
   */
  getCartItems(): Observable<CartItem[]> {
    console.log('🛒 Fetching cart items from:', this.apiUrl);
    
    if (!this.authService.isLoggedIn()) {
      console.log('❌ User not logged in');
      return of([]);
    }
    
    const token = localStorage.getItem('token');
    const headers = new HttpHeaders({
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${token}`
    });

    return this.http.get<CartItem[]>(this.apiUrl, { headers }).pipe(
      tap(items => {
        console.log('✅ Cart items received:', items.length);
        this.cartItemsSubject.next(items);
        this.cartCountSubject.next(items.length);
        this.authService.updateCartCount(items.length);
      }),
      catchError(this.handleError.bind(this))
    );
  }

  /**
   * Add a product to cart
   */
  addToCart(productId: number, quantity: number): Observable<any> {
    console.log('➕ Adding to cart:', { productId, quantity });
    
    if (!this.authService.isLoggedIn()) {
      return throwError(() => ({ error: 'Please login to add items to cart' }));
    }
    
    const token = localStorage.getItem('token');
    const headers = new HttpHeaders({
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${token}`
    });

    return this.http.post(this.apiUrl, { productId, quantity }, { headers }).pipe(
      tap(response => {
        console.log('✅ Add to cart response:', response);
        this.refreshCart(); // Refresh cart after adding
      }),
      catchError(this.handleError.bind(this))
    );
  }

  /**
   * Update quantity of a cart item
   */
  updateCartItem(itemId: number, quantity: number): Observable<any> {
    console.log('🔄 Updating cart item:', { itemId, quantity });
    
    const token = localStorage.getItem('token');
    const headers = new HttpHeaders({
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${token}`
    });

    return this.http.put(`${this.apiUrl}/${itemId}`, { quantity }, { headers }).pipe(
      tap(response => {
        console.log('✅ Update response:', response);
        this.refreshCart(); // Refresh cart after update
      }),
      catchError(this.handleError.bind(this))
    );
  }

  /**
   * Remove an item from cart
   */
  removeFromCart(itemId: number): Observable<any> {
    console.log('🗑️ Removing cart item:', itemId);
    
    const token = localStorage.getItem('token');
    const headers = new HttpHeaders({
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${token}`
    });

    return this.http.delete(`${this.apiUrl}/${itemId}`, { headers }).pipe(
      tap(response => {
        console.log('✅ Remove response:', response);
        this.refreshCart(); // Refresh cart after removal
      }),
      catchError(this.handleError.bind(this))
    );
  }

  /**
   * Clear entire cart (after successful payment)
   */
  clearCart(): Observable<any> {
    console.log('🧹 Clearing cart after payment...');
    
    if (!this.authService.isLoggedIn()) {
      this.clearLocalCart();
      return of({ success: true, message: 'Cart cleared locally' });
    }
    
    const token = localStorage.getItem('token');
    const headers = new HttpHeaders({
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${token}`
    });

    // Call the clear endpoint
    return this.http.delete(`${this.apiUrl}/clear`, { headers }).pipe(
      tap(response => {
        console.log('✅ Cart cleared successfully on server:', response);
        this.clearLocalCart(); // Clear local state
      }),
      catchError(error => {
        console.error('❌ Error clearing cart on server:', error);
        // Even if server fails, clear local cart
        this.clearLocalCart();
        // Return success to not break the flow
        return of({ success: true, message: 'Cart cleared locally', error: error });
      })
    );
  }

  /**
   * Clear local cart state
   */
  private clearLocalCart(): void {
    console.log('Clearing local cart state');
    this.cartItemsSubject.next([]);
    this.cartCountSubject.next(0);
    this.authService.updateCartCount(0);
  }

  /**
   * Get current cart count
   */
  getCartCount(): void {
    if (!this.authService.isLoggedIn()) {
      this.cartCountSubject.next(0);
      return;
    }

    this.getCartItems().subscribe({
      next: (items) => {
        this.cartCountSubject.next(items.length);
        this.authService.updateCartCount(items.length);
      },
      error: (error) => {
        console.error('❌ Error fetching cart count:', error);
        if (error.status === 401) {
          // Token expired, redirect to login
          this.authService.logout();
        }
      }
    });
  }

  /**
   * Manual update cart count (used for optimistic updates)
   */
  updateCartCount(count: number): void {
    this.cartCountSubject.next(count);
    this.authService.updateCartCount(count);
  }

  /**
   * Refresh cart count from server
   */
  refreshCartCount(): void {
    this.refreshCart();
  }

  /**
   * Get cart total amount
   */
  getCartTotal(): Observable<number> {
    return this.getCartItems().pipe(
      map(items => {
        return items.reduce((total, item) => total + (item.price * item.quantity), 0);
      })
    );
  }

  /**
   * Check if cart is empty
   */
  isCartEmpty(): Observable<boolean> {
    return this.getCartItems().pipe(
      map(items => items.length === 0)
    );
  }

  /**
   * Error handler
   */
  private handleError(error: HttpErrorResponse) {
    console.error('❌ Cart service error:', error);
    
    let errorMessage = 'An error occurred';
    let statusCode = error.status;
    
    if (error.error instanceof ErrorEvent) {
      // Client-side error
      errorMessage = error.error.message;
      console.error('Client error:', errorMessage);
    } else {
      // Server-side error
      console.error(
        `Backend returned code ${error.status}, ` +
        `body was:`, error.error
      );
      
      if (error.status === 0) {
        errorMessage = 'Cannot connect to server. Please check if backend is running.';
      } else if (error.status === 401) {
        errorMessage = 'Your session has expired. Please login again.';
        // Trigger logout
        this.authService.logout();
      } else if (error.status === 403) {
        errorMessage = 'You do not have permission to perform this action.';
      } else if (error.status === 404) {
        errorMessage = 'Cart item not found.';
      } else if (error.status === 500) {
        errorMessage = 'Server error. Please try again later.';
      } else {
        errorMessage = error.error?.error || error.message || 'Unknown error occurred';
      }
    }
    
    // Return an observable with a user-facing error message
    return throwError(() => ({
      status: statusCode,
      error: errorMessage,
      details: error.error
    }));
  }

  /**
   * Get cart count as observable (for components to subscribe)
   */
  getCartCountObservable(): Observable<number> {
    return this.cartCount$;
  }

  /**
   * Get cart items as observable
   */
  getCartItemsObservable(): Observable<CartItem[]> {
    return this.cartItems$;
  }
}
